def client_ip(request: Request) -> str:
    if os.getenv("TRUST_PROXY", "0") == "1":
        forwarded = request.headers.get("x-forwarded-for")
        if forwarded:
            return forwarded.split(",")[0].strip()
    return request.client.host if request.client else "unknown"


def keyed(scope: str, value: str) -> str:
    digest = hmac.new(SECRET_BYTES, value.encode(), hashlib.sha256).hexdigest()
    return f"{scope}:{digest}"


async def enforce_rate(key: str, limit: int, window_seconds: int):
    allowed, retry_after = await limiter.check(key, limit, window_seconds)
    if not allowed:
        raise ApiError(
            429,
            [err("request", "rate_limited", "Too many registration attempts. Try again later.")],
            {"Retry-After": str(retry_after)},
        )


async def registration_ip_rate_limit(request: Request):
    ip = client_ip(request)
    await enforce_rate(f"register:ip:min:{ip}", 20, 60)
    await enforce_rate(f"register:ip:hour:{ip}", 100, 3600)


async def enforce_json_csrf(request: Request):
    content_type = request.headers.get("content-type", "").split(";")[0].lower()
    if content_type != "application/json":
        raise ApiError(415, [err("request", "content_type", "Content-Type must be application/json.")])

    origin = request.headers.get("origin")
    if origin and ALLOWED_ORIGINS and origin not in ALLOWED_ORIGINS:
        raise ApiError(403, [err("request", "origin_not_allowed", "Request origin is not allowed.")])

    if request.headers.get("sec-fetch-site") == "cross-site":
        raise ApiError(403, [err("request", "csrf", "Cross-site registration requests are not allowed.")])

    if request.cookies:
        cookie_token = request.cookies.get("csrf_token", "")
        header_token = request.headers.get("x-csrf-token", "")
        if not cookie_token or not header_token or not hmac.compare_digest(cookie_token, header_token):
            raise ApiError(403, [err("request", "csrf", "Invalid CSRF token.")])


class DuplicateJSONKey(ValueError):
    pass


def reject_duplicate_keys(pairs):
    obj = {}
    for key, value in pairs:
        if key in obj:
            raise DuplicateJSONKey(key)
        obj[key] = value
    return obj


async def parse_body(request: Request) -> dict[str, Any]:
    body = await request.body()
    if not body:
        raise ApiError(400, [err("request", "empty_body", "Request body is required.")])
    if len(body) > MAX_BODY_BYTES:
        raise ApiError(413, [err("request", "body_too_large", "Request body is too large.")])
    try:
        data = json.loads(body, object_pairs_hook=reject_duplicate_keys)
    except DuplicateJSONKey:
        raise ApiError(400, [err("request", "duplicate_json_key", "Duplicate JSON keys are not allowed.")])
    except json.JSONDecodeError:
        raise ApiError(400, [err("request", "invalid_json", "Request body must be valid JSON.")])
    if not isinstance(data, dict):
        raise ApiError(422, [err("request", "invalid_shape", "Request body must be a JSON object.")])
    return data


def has_forbidden_unicode(value: str) -> bool:
    for ch in value:
        category = unicodedata.category(ch)
        bidi = unicodedata.bidirectional(ch)
        if category.startswith("C"):
            return True
        if bidi in {"RLO", "LRO", "RLE", "LRE", "PDF", "RLI", "LRI", "FSI", "PDI"}:
            return True
    return False


def simple_skeleton(value: str) -> str:
    table = str.maketrans({"0": "o", "1": "i", "3": "e", "4": "a", "5": "s", "7": "t", "$": "s", "@": "a"})
    return value.casefold().translate(table)


def contains_abuse_term(value: str) -> bool:
    skel = simple_skeleton(value)
    return any(term in skel for term in ABUSE_TERMS)


def validate_email_field(value: Any, errors: list[dict[str, str]]) -> dict[str, str] | None:
    if not isinstance(value, str):
        errors.append(err("email", "type", "Email must be a string."))
        return None

    if value != value.strip():
        errors.append(err("email", "whitespace", "Email must not contain surrounding whitespace."))

    raw = unicodedata.normalize("NFKC", value.strip())
    if not raw:
        errors.append(err("email", "required", "Email is required."))
        return None
    if has_forbidden_unicode(raw):
        errors.append(err("email", "control_chars", "Email contains forbidden control or invisible characters."))
    if len(raw) > 254 or len(raw.encode("utf-8")) > 320:
        errors.append(err("email", "too_long", "Email is too long."))
    if raw.count("@") != 1:
        errors.append(err("email", "format", "Email must contain exactly one @ sign."))

    try:
        parsed = validate_email(
            raw,
            allow_smtputf8=False,
            allow_quoted_local=False,
            allow_domain_literal=False,
            check_deliverability=False,
            globally_deliverable=True,
        )
    except EmailNotValidError:
        errors.append(err("email", "format", "Email address is not valid."))
        return None

    local = parsed.local_part
    domain_unicode = parsed.domain.casefold()

    try:
        domain_ascii = idna.encode(domain_unicode, uts46=True, std3_rules=True).decode("ascii").casefold()
    except idna.IDNAError:
        errors.append(err("email", "idn", "Email domain is not a valid internationalized domain name."))
        return None

    email_canonical = f"{local.casefold()}@{domain_ascii}"

    if len(local) > 64:
        errors.append(err("email", "local_too_long", "Email local part is too long."))
    if not EMAIL_LOCAL_RE.fullmatch(local):
        errors.append(err("email", "local_chars", "Email local part contains unsupported characters."))
    if local.startswith(".") or local.endswith(".") or ".." in local:
        errors.append(err("email", "local_dots", "Email local part has invalid dot placement."))

    labels = domain_ascii.split(".")
    if len(labels) < 2:
        errors.append(err("email", "domain", "Email domain must include a public suffix."))
    for label in labels:
        if not label or len(label) > 63:
            errors.append(err("email", "domain_label", "Email domain has an invalid label."))
            break
        if label.startswith("-") or label.endswith("-") or not re.fullmatch(r"[a-z0-9-]+", label):
            errors.append(err("email", "domain_label", "Email domain has invalid label characters."))
            break
    if domain_ascii in RESERVED_DOMAINS or any(domain_ascii.endswith(s) for s in RESERVED_DOMAIN_SUFFIXES):
        errors.append(err("email", "reserved_domain", "Email domain is not allowed."))
    if domain_ascii in DISPOSABLE_DOMAINS or any(domain_ascii.endswith("." + d) for d in DISPOSABLE_DOMAINS):
        errors.append(err("email", "disposable_domain", "Disposable email addresses are not allowed."))
    if CHECK_EMAIL_DNS and not domain_accepts_mail(domain_ascii):
        errors.append(err("email", "domain_unreachable", "Email domain does not appear to accept mail."))

    return {
        "email": email_canonical,
        "email_canonical": email_canonical,
        "email_domain_ascii": domain_ascii,
        "email_local": local.casefold(),
    }


@lru_cache(maxsize=4096)
def domain_accepts_mail(domain_ascii: str) -> bool:
    resolver = dns.resolver.Resolver()
    resolver.timeout = 1.0
    resolver.lifetime = 2.0

    try:
        answers = resolver.resolve(domain_ascii, "MX")
        if any(str(r.exchange).strip(".") for r in answers):
            return True
    except Exception:
        pass

    for record_type in ("A", "AAAA"):
        try:
            resolver.resolve(domain_ascii, record_type)
            return True
        except Exception:
            pass

    return False


def validate_username_field(value: Any, errors: list[dict[str, str]]) -> str | None:
    if not isinstance(value, str):
        errors.append(err("username", "type", "Username must be a string."))
        return None

    if value != value.strip():
        errors.append(err("username", "whitespace", "Username must not contain surrounding whitespace."))

    raw = value.strip()
    normalized = unicodedata.normalize("NFKC", raw)
    username = normalized.casefold()

    if not username:
        errors.append(err("username", "required", "Username is required."))
        return None
    if normalized != raw:
        errors.append(err("username", "unicode_normalization", "Username contains confusable Unicode characters."))
    if has_forbidden_unicode(username):
        errors.append(err("username", "control_chars", "Username contains forbidden control or invisible characters."))
    if not username.isascii():
        errors.append(err("username", "ascii_only", "Username must use ASCII characters only."))
    if len(username) < 3:
        errors.append(err("username", "too_short", "Username must be at least 3 characters."))
    if len(username) > 32 or len(username.encode("utf-8")) > 64:
        errors.append(err("username", "too_long", "Username must be at most 32 characters."))
    if not USERNAME_RE.fullmatch(username):
        errors.append(err("username", "characters", "Username may contain lowercase letters, numbers, dots, hyphens, and underscores."))
    if re.search(r"[._-]{2,}", username):
        errors.append(err("username", "repeated_separator", "Username must not contain repeated separators."))
    if username.isdigit():
        errors.append(err("username", "all_numeric", "Username must not be entirely numeric."))
    if username in RESERVED_USERNAMES or re.fullmatch(r"(admin|support|staff|root|system)[._-]?\d*", username):
        errors.append(err("username", "reserved", "Username is reserved."))
    if contains_abuse_term(username):
        errors.append(err("username", "blocked_content", "Username is not allowed."))

    return username


def validate_display_name_field(value: Any, errors: list[dict[str, str]]) -> tuple[str | None, str | None]:
    if not isinstance(value, str):
        errors.append(err("display_name", "type", "Display name must be a string."))
        return None, None

    raw = unicodedata.normalize("NFKC", value).strip()
    collapsed = re.sub(r"\s+", " ", raw)

    if not collapsed:
        errors.append(err("display_name", "required", "Display name is required."))
        return None, None
    if has_forbidden_unicode(collapsed):
        errors.append(err("display_name", "control_chars", "Display name contains forbidden control or invisible characters."))
    if len(collapsed) > 80 or len(collapsed.encode("utf-8")) > 160:
        errors.append(err("display_name", "too_long", "Display name is too long."))
    if contains_abuse_term(collapsed):
        errors.append(err("display_name", "blocked_content", "Display name is not allowed."))
    if collapsed.casefold() in RESERVED_USERNAMES:
        errors.append(err("display_name", "impersonation", "Display name is reserved."))

    sanitized = bleach.clean(collapsed, tags=[], attributes={}, protocols=[], strip=True)
    if html.unescape(sanitized) != collapsed:
        errors.append(err("display_name", "html", "Display name must not contain HTML or scripts."))

    return sanitized, collapsed


def has_sequence(password: str) -> bool:
    compact = re.sub(r"[^a-z0-9]", "", password.casefold())
    sequences = [
        string.ascii_lowercase,
        string.ascii_lowercase[::-1],
        string.digits,
        string.digits[::-1],
        "qwertyuiop",
        "poiuytrewq",
        "asdfghjkl",
        "lkjhgfdsa",
        "zxcvbnm",
        "mnbvcxz",
    ]
    for i in range(max(0, len(compact) - 3)):
        chunk = compact[i:i + 4]
        if any(chunk in seq for seq in sequences):
            return True
    return False


async def validate_password_field(
    value: Any,
    username: str | None,
    email_info: dict[str, str] | None,
    display_name_plain: str | None,
    errors: list[dict[str, str]],
) -> str | None:
    if not isinstance(value, str):
        errors.append(err("password", "type", "Password must be a string."))
        return None

    password = unicodedata.normalize("NFC", value)

    if value != password:
        errors.append(err("password", "unicode_normalization", "Password contains unstable Unicode normalization."))
    if password != password.strip():
        errors.append(err("password", "surrounding_whitespace", "Password must not start or end with whitespace."))
    if not password:
        errors.append(err("password", "required", "Password is required."))
        return None
    if has_forbidden_unicode(password):
        errors.append(err("password", "control_chars", "Password contains forbidden control or invisible characters."))
    if len(password) < 12:
        errors.append(err("password", "too_short", "Password must be at least 12 characters."))
    if len(password) > 128 or len(password.encode("utf-8")) > 256:
        errors.append(err("password", "too_long", "Password is too long."))
        return None

    classes = {
        "lowercase": any(c.islower() for c in password),
        "uppercase": any(c.isupper() for c in password),
        "digit": any(c.isdigit() for c in password),
        "symbol": any(not c.isalnum() and not c.isspace() for c in password),
    }
    for name, present in classes.items():
        if not present:
            errors.append(err("password", f"missing_{name}", f"Password must include at least one {name} character."))

    folded = password.casefold()
    if folded in COMMON_PASSWORDS:
        errors.append(err("password", "common", "Password is too common."))
    if len(set(folded)) < 5:
        errors.append(err("password", "low_variety", "Password must contain more unique characters."))
    if re.search(r"(.)\1\1\1", folded):
        errors.append(err("password", "repeated_chars", "Password must not contain long repeated character runs."))
    if has_sequence(password):
        errors.append(err("password", "sequence", "Password must not contain obvious keyboard or numeric sequences."))

    personal_tokens = set()
    if username:
        personal_tokens.add(username.casefold())
    if email_info:
        personal_tokens.add(email_info["email_local"].casefold())
        personal_tokens.add(email_info["email_domain_ascii"].split(".")[0].casefold())
    if display_name_plain:
        personal_tokens.update(t.casefold() for t in re.split(r"[^A-Za-z0-9]+", display_name_plain) if len(t) >= 3)

    for token in {t for t in personal_tokens if len(t) >= 3}:
        if token in folded:
            errors.append(err("password", "contains_personal_info", "Password must not contain your email, username, or display name."))
            break
        if len(token) >= 6 and SequenceMatcher(None, folded, token).ratio() >= 0.75:
            errors.append(err("password", "similar_personal_info", "Password is too similar to your email, username, or display name."))
            break

    if CHECK_BREACHED_PASSWORDS:
        breached, unavailable = await password_is_breached(password)
        if breached:
            errors.append(err("password", "breached", "Password appears in known data breaches."))
        elif unavailable and ENFORCE_BREACH_CHECK:
            errors.append(err("password", "breach_check_unavailable", "Password breach status could not be verified."))

    return password


HIBP_CACHE: dict[str, str] = {}


async def password_is_breached(password: str) -> tuple[bool, bool]:
    # SHA-1 is only used for HIBP k-anonymity lookup; stored password hash is Argon2id.
    sha1 = hashlib.sha1(password.encode("utf-8")).hexdigest().upper()
    prefix, suffix = sha1[:5], sha1[5:]

    if prefix not in HIBP_CACHE:
        try:
            async with httpx.AsyncClient(timeout=3.0) as client:
                response = await client.get(
                    f"https://api.pwnedpasswords.com/range/{prefix}",
                    headers={
                        "Add-Padding": "true",
                        "User-Agent": "secure-registration-service",
                    },
                )
            if response.status_code != 200:
                return False, True
            HIBP_CACHE[prefix] = response.text
        except httpx.HTTPError:
            return False, True

    for line in HIBP_CACHE[prefix].splitlines():
        candidate = line.split(":", 1)[0].upper()
        if hmac.compare_digest(candidate, suffix):
            return True, False
    return False, False


async def validate_registration(data: dict[str, Any]) -> tuple[dict[str, Any] | None, list[dict[str, str]]]:
    errors: list[dict[str, str]] = []

    for field in sorted(REQUIRED_FIELDS - data.keys()):
        errors.append(err(field, "required", f"{field} is required."))
    for field in sorted(data.keys() - REQUIRED_FIELDS):
        errors.append(err("request", "unknown_field", "Request contains unsupported fields."))

    email_info = validate_email_field(data.get("email"), errors) if "email" in data else None
    username = validate_username_field(data.get("username"), errors) if "username" in data else None
    display_name, display_name_plain = (
        validate_display_name_field(data.get("display_name"), errors)
        if "display_name" in data else (None, None)
    )
    password = await validate_password_field(
        data.get("password"),
        username,
        email_info,
        display_name_plain,
        errors,
    ) if "password" in data else None

    if errors:
        return None, errors

    return {
        "email": email_info["email"],
        "email_canonical": email_info["email_canonical"],
        "email_domain_ascii": email_info["email_domain_ascii"],
        "username": username,
        "username_canonical": username,
        "display_name": display_name,
        "password": password,
    }, []


def password_material(password: str) -> str:
    if not PASSWORD_PEPPER:
        return password
    return hmac.new(PASSWORD_PEPPER.encode(), password.encode("utf-8"), hashlib.sha256).hexdigest()


def hash_password(password: str) -> str:
    return PASSWORD_HASHER.hash(password_material(password))


def db() -> sqlite3.Connection:
    conn = sqlite3.connect(DB_PATH, isolation_level=None)
    conn.execute("PRAGMA foreign_keys = ON")
    conn.execute("PRAGMA journal_mode = WAL")
    conn.execute("PRAGMA busy_timeout = 5000")
    return conn


def init_db():
    with db() as conn:
        conn.execute("""
            CREATE TABLE IF NOT EXISTS users (
                id INTEGER PRIMARY KEY AUTOINCREMENT,
                email TEXT NOT NULL,
                email_canonical TEXT NOT NULL UNIQUE,
                email_domain_ascii TEXT NOT NULL,
                username TEXT NOT NULL,
                username_canonical TEXT NOT NULL UNIQUE,
                display_name TEXT NOT NULL,
                password_hash TEXT NOT NULL,
                email_verified INTEGER NOT NULL DEFAULT 0,
                status TEXT NOT NULL DEFAULT 'pending',
                created_at TEXT NOT NULL,
                CHECK (length(email_canonical) <= 254),
                CHECK (length(username_canonical) BETWEEN 3 AND 32),
                CHECK (length(display_name) BETWEEN 1 AND 160)
            )
        """)


@app.on_event("startup")
def on_startup():
    init_db()


def insert_user(clean: dict[str, Any], password_hash: str) -> bool:
    now = datetime.now(timezone.utc).isoformat()

    conn = db()
    try:
        conn.execute("BEGIN IMMEDIATE")
        conn.execute(
            """
            INSERT INTO users (
                email, email_canonical, email_domain_ascii,
                username, username_canonical, display_name,
                password_hash, created_at
            )
            VALUES (?, ?, ?, ?, ?, ?, ?, ?)
            """,
            (
                clean["email"],
                clean["email_canonical"],
                clean["email_domain_ascii"],
                clean["username"],
                clean["username_canonical"],
                clean["display_name"],
                password_hash,
                now,
            ),
        )
        conn.commit()
        return True
    except sqlite3.IntegrityError as exc:
        conn.rollback()
        if "unique constraint failed" in str(exc).casefold():
            return False
        raise
    finally:
        conn.close()


@app.post(
    "/api/register",
    dependencies=[Depends(enforce_json_csrf), Depends(registration_ip_rate_limit)],
)
async def register(request: Request):
    data = await parse_body(request)

    raw_identity = "|".join(
        str(data.get(field, "")).strip().casefold()[:254]
        for field in ("email", "username")
    )
    await enforce_rate(keyed("register:identity", raw_identity), 8, 600)

    clean, errors = await validate_registration(data)
    if errors:
        return JSONResponse(status_code=422, content={"ok": False, "errors": errors})

    pwd_hash = hash_password(clean["password"])
    insert_user(clean, pwd_hash)

    # Same response for both newly-created and duplicate identities.
    return JSONResponse(
        status_code=202,
        content={
            "ok": True,
            "message": "If registration can be completed, you will receive the next step by email.",
        },
    )
